    IF (NEW.DETALLE_ID IS NULL) THEN
        NEW.DETALLE_ID = GEN_ID(SEQ_ORDEN_COMPRA_DETALLE, 1);
END
^


/* Trigger: TR_PRODUCTO_SINCRONIZACION_ID */
CREATE OR ALTER TRIGGER TR_PRODUCTO_SINCRONIZACION_ID FOR PRODUCTO_SINCRONIZACION
ACTIVE BEFORE INSERT POSITION 0
AS
BEGIN
    IF (NEW.SINCRONIZACION_ID IS NULL) THEN
        NEW.SINCRONIZACION_ID = GEN_ID(SEQ_PRODUCTO_SINCRONIZACION, 1);
END
^

SET TERM ; ^



